+    fn command_gate_required_dcg_failure_redacts_echoed_command() {
+        let config = CommandGateConfig {
+            enabled: true,
+            dcg_mode: DcgMode::Required,
+            dcg_deny_policy: DcgDenyPolicy::RequireApproval,
+        };
